    39→export default function TenderFormBuilder() {
    40→  const [, navigate] = useLocation();
    41→  const { t } = useI18n();
    42→
    43→  // Initialize cards - check for saved template/state first, then fall back to required cards
    44→  const [cards, setCards] = useState<FormCard[]>(() => {
    45→    const savedState = localStorage.getItem(TENDER_STATE_KEY);
    46→    if (savedState) {
    47→      try {
    48→        const parsedCards = JSON.parse(savedState);
    49→        if (Array.isArray(parsedCards) && parsedCards.length > 0) {
    50→          // Sync labels from the current library for non-custom cards so label
    51→          // changes in the library are always reflected on the canvas.
    52→          return parsedCards.map((card: FormCard) => {
    53→            const definition = getCardDefinition(card.type);
    54→            if (definition && !definition.isCustom) {
    55→              return { ...card, label: definition.label };
    56→            }
    57→            return card;
    58→          });
    59→        }
    60→      } catch (e) {
    61→        console.error("Error parsing saved cards:", e);
    62→      }
    63→    }
    64→    // Fall back to default required cards
    65→    return CARD_LIBRARY.required.map((def) => createFormCard(def));
    66→  });
    67→
    68→  const [activeId, setActiveId] = useState<string | null>(null);
    69→  const [activeDragData, setActiveDragData] = useState<any>(null);
    70→  const [insightCardType, setInsightCardType] = useState<CardType | null>(null);
    71→  const [cursorPos, setCursorPos] = useState<{ x: number; y: number } | null>(null);
    72→
    73→  // Sidebar resize state — default 50%, min 40%, max 60% of viewport
    74→  const [sidebarWidth, setSidebarWidth] = useState(() => {
    75→    const saved = localStorage.getItem("tender_sidebar_width");
    76→    if (saved) {
    77→      const parsed = parseInt(saved, 10);
    78→      const min = Math.round(window.innerWidth * 0.40);
    79→      const max = Math.round(window.innerWidth * 0.60);
    80→      if (!isNaN(parsed) && parsed >= min && parsed <= max) return parsed;
    81→    }
    82→    return Math.round(window.innerWidth * 0.50);
    83→  });
    84→  const [sidebarVisible, setSidebarVisible] = useState(true);
    85→  const isResizing = useRef(false);
    86→
    87→  const handleMouseDown = useCallback((e: React.MouseEvent) => {
    88→    isResizing.current = true;
    89→    document.addEventListener('mousemove', handleMouseMove);
    90→    document.addEventListener('mouseup', handleMouseUp);
    91→    document.body.style.cursor = 'col-resize';
    92→    document.body.style.userSelect = 'none';
    93→  }, []);
    94→
    95→  const handleMouseMove = useCallback((e: MouseEvent) => {
    96→    if (!isResizing.current) return;
    97→    const min = Math.round(window.innerWidth * 0.40);
    98→    const max = Math.round(window.innerWidth * 0.60);
    99→    const newWidth = Math.min(max, Math.max(min, window.innerWidth - e.clientX));
   100→    setSidebarWidth(newWidth);
   101→    localStorage.setItem("tender_sidebar_width", String(newWidth));
   102→  }, []);
   103→
   104→  const handleMouseUp = useCallback(() => {
   105→    isResizing.current = false;
   106→    document.removeEventListener('mousemove', handleMouseMove);
   107→    document.removeEventListener('mouseup', handleMouseUp);
   108→    document.body.style.cursor = '';
   109→    document.body.style.userSelect = '';
   110→  }, [handleMouseMove]);
   111→
   112→  const sensors = useSensors(
   113→    useSensor(PointerSensor, {
   114→      activationConstraint: {
   115→        distance: 8,
   116→      },
   117→    }),
   118→    useSensor(KeyboardSensor, {
   119→      coordinateGetter: sortableKeyboardCoordinates,
   120→    })
   121→  );
   122→
   123→  // Get list of card types already in the form
   124→  const usedCardTypes = cards.map((c) => c.type);
   125→
   126→  // Step 1 is valid as long as the user has at least the required cards (always true)
   127→  const canContinue = cards.length > 0;
   128→
   129→  const handleDragStart = useCallback((event: DragStartEvent) => {
   130→    setActiveId(event.active.id as string);
   131→    setActiveDragData(event.active.data.current);
   132→  }, []);
   133→
   134→  const handleDragEnd = useCallback(
   135→    (event: DragEndEvent) => {
   136→      const { active, over } = event;
   137→
   138→      setActiveId(null);
   139→      setActiveDragData(null);
   140→
   141→      if (!over) return;
   142→
   143→      const activeData = active.data.current;
   144→
   145→      // Handle dropping from library
   146→      if (activeData?.type === "library-card") {
   147→        const cardDefinition = activeData.cardDefinition as CardDefinition;
   148→
   149→        // Check if non-custom card is already in form
   150→        if (
   151→          !cardDefinition.isCustom &&
   152→          usedCardTypes.includes(cardDefinition.type)
   153→        ) {
   154→          return;
   155→        }
   156→
   157→        // Create new card and add to form
   158→        const newCard = createFormCard(cardDefinition);
   159→        setCards((prev) => [...prev, newCard]);
   160→        return;
   161→      }
   162→
   163→      // Handle reordering within canvas
   164→      if (active.id !== over.id) {
   165→        setCards((items) => {
   166→          const oldIndex = items.findIndex((i) => i.id === active.id);
   167→          const newIndex = items.findIndex((i) => i.id === over.id);
   168→
   169→          if (oldIndex !== -1 && newIndex !== -1) {
   170→            return arrayMove(items, oldIndex, newIndex);
   171→          }
   172→          return items;
   173→        });
   174→      }
   175→    },
   176→    [usedCardTypes]
   177→  );
   178→
   179→  const handleRemoveCard = useCallback((id: string) => {
   180→    setCards((prev) => prev.filter((c) => c.id !== id));
   181→  }, []);
   182→
   183→  const handleUpdateCard = useCallback(
   184→    (id: string, updates: Partial<FormCard>) => {
   185→      setCards((prev) =>
   186→        prev.map((c) => (c.id === id ? { ...c, ...updates } : c))
