   200→  };
   201→
   202→  // Render drag overlay
   203→  const renderDragOverlay = () => {
   204→    if (!activeId || !activeDragData) return null;
   205→
   206→    if (activeDragData.type === "library-card") {
   207→      const def = activeDragData.cardDefinition as CardDefinition;
   208→      return (
   209→        <div className="opacity-80">
   210→          <LibraryCard
