   221→    const card = cards.find((c) => c.id === activeId);
   222→    if (card) {
   223→      return <DraggableCard card={card} isOverlay />;
   224→    }
   225→
   226→    return null;
   227→  };
   228→
   229→  return (
   230→    <DndContext
   231→      sensors={sensors}
   232→      collisionDetection={closestCenter}
   233→      onDragStart={handleDragStart}
   234→      onDragEnd={handleDragEnd}
   235→    >
   236→      <div className="h-screen flex flex-col bg-gray-50 dark:bg-gray-950">
   237→        {/* Header */}
   238→        <header className="flex-shrink-0 bg-white dark:bg-gray-900 border-b border-gray-200 dark:border-gray-700 px-6 py-4">
   239→          <div className="flex items-center justify-between">
   240→            <div className="flex items-center gap-4">
   241→              <img
   242→                src={logoPath}
   243→                alt="Bid"
   244→                className="h-10 cursor-pointer hover:opacity-80 transition-opacity"
   245→                onClick={() => navigate("/dashboard")}
   246→              />
   247→              <div className="h-6 w-px bg-gray-200 dark:bg-gray-700" />
   248→              <div>
   249→                <h1 className="text-lg font-semibold text-gray-900 dark:text-white">
   250→                  {t('tenderFlow.formBuilderTitle')}
   251→                </h1>
   252→                <p className="text-xs text-gray-500 dark:text-gray-400">
   253→                  {t('tenderFlow.formBuilderSubtitle')}
   254→                </p>
   255→              </div>
   256→            </div>
   257→
   258→            <StepIndicator
   259→              steps={[{ label: t('tenderFlow.stepStructure') }, { label: t('tenderFlow.stepFillDetails') }, { label: t('tenderFlow.stepReview') }]}
   260→              currentStep={1}
   261→            />
   262→
   263→            <div className="flex items-center gap-3">
   264→              <Button variant="outline" onClick={handleBack}>
   265→                <ArrowLeft className="h-4 w-4 mr-2" />
   266→                {t('tenderFlow.back')}
   267→              </Button>
   268→              <Button
   269→                onClick={handleContinue}
   270→                disabled={!canContinue}
   271→                className="bg-[#E25E45] hover:bg-[#d54d35] text-white"
   272→              >
   273→                {t('tenderFlow.continueToDetails')}
   274→                <ArrowRight className="h-4 w-4 ml-2" />
   275→              </Button>
   276→            </div>
   277→          </div>
   278→        </header>
   279→
   280→        {/* Main Content */}
   281→        <div className="flex-1 flex overflow-hidden">
   282→          <FormBuilderCanvas
   283→            cards={cards}
   284→            onRemoveCard={handleRemoveCard}
   285→            onUpdateCard={handleUpdateCard}
   286→            sidebarVisible={sidebarVisible}
   287→            onToggleSidebar={() => setSidebarVisible(!sidebarVisible)}
   288→            structureOnly={true}
   289→          />
   290→
   291→          <AnimatePresence mode="wait">
   292→            {sidebarVisible && (
   293→              <motion.div
   294→                key="sidebar"
   295→                initial={{ width: 0 }}
   296→                animate={{ width: sidebarWidth + 4 }}
   297→                exit={{ width: 0 }}
   298→                transition={{ duration: 0.2, ease: "easeInOut" }}
   299→                className="flex flex-shrink-0 overflow-hidden"
   300→              >
   301→                {/* Resize Handle - left of sidebar */}
   302→                <div
   303→                  onMouseDown={handleMouseDown}
   304→                  className="w-1 hover:w-1.5 bg-gray-200 dark:bg-gray-700 hover:bg-[#E25E45] cursor-col-resize transition-all flex-shrink-0 group relative"
   305→                >
   306→                  <div className="absolute inset-y-0 -left-1 -right-1 group-hover:bg-[#E25E45]/10" />
   307→                </div>
   308→
   309→                <CardLibrarySidebar
   310→                  usedCardTypes={usedCardTypes}
   311→                  width={sidebarWidth}
   312→                  onShowInsight={(type, pos) => {
   313→                    setInsightCardType(type);
   314→                    setCursorPos(pos ?? null);
   315→                  }}
   316→                  onHideInsight={() => {
   317→                    setInsightCardType(null);
   318→                    setCursorPos(null);
   319→                  }}
   320→                />
   321→              </motion.div>
   322→            )}
   323→          </AnimatePresence>
   324→        </div>
   325→
   326→        {/* Drag Overlay */}
   327→        <DragOverlay>
   328→          {renderDragOverlay()}
   329→        </DragOverlay>
   330→
   331→        {/* Field Insight Panel */}
   332→        <FieldInsightPanel
   333→          cardType={insightCardType}
   334→          cursorPos={cursorPos}
   335→          onClose={() => { setInsightCardType(null); setCursorPos(null); }}
   336→        />
   337→      </div>
   338→    </DndContext>
   339→  );
   340→}
